// Get the PDF text content and record info
const pdfText = $input.item.json.text || '';
const recordId = $input.item.json.id || '';

// Safely access fields - handle case where fields object might be undefined
const fields = $input.item.json.fields || {};
const auctionTitle = fields["Auction"] || "Unknown Auction";

// Log basic info for debugging
console.log("Processing PDF content for auction ID:", recordId);
console.log("Auction Title:", auctionTitle);
console.log("PDF extracted text length:", pdfText.length);

// See if we have metadata about the PDF pages
const numPages = $input.item.json.numpages || 1;
console.log("PDF has", numPages, "pages");

// Split the text into lines for processing
const lines = pdfText.split('\n');

// Initialize array to store foreclosure records
const foreclosures = [];

// Use a simplified approach to extract basic data patterns
let inDataSection = false;
let currentRow = {};

// Track if we've found any valid entries
let foundValidEntries = false;

for (let i = 0; i < lines.length; i++) {
  const line = lines[i].trim();

  // Check if this line contains the column headers
  if (line.includes("PARCEL") && (line.includes("TOWN") || line.includes("SBL"))) {
    inDataSection = true;
    continue;
  }

  // Skip empty lines or header rows
  if (!inDataSection || line === '' || line.includes("Page |")) {
    continue;
  }

  // Try to identify a row that starts with a number (likely a parcel entry)
  const rowStartMatch = line.match(/^\s*(\d+)\s+([A-Za-z]+)/);

  if (rowStartMatch) {
    // If we already have a row in progress, save it
    if (Object.keys(currentRow).length > 0) {
      foreclosures.push({...currentRow});
    }

    // Start a new row
    const parcelNum = rowStartMatch[1].trim();
    const town = rowStartMatch[2].trim();

    currentRow = {
      parcelNumber: parcelNum,
      town: town
    };

    // Look for SBL in standard format
    const sblMatch = line.match(/([\d]{3}\.[\d]{3}-[\d]{4}-[\d]{3}\.[\d]{3}-[\d]{4})/);
    if (sblMatch) {
      currentRow.sbl = sblMatch[1];
    }

    // Look for dollar amounts
    const moneyMatches = line.match(/\$([\d,]+\.\d{2})/g);
    if (moneyMatches && moneyMatches.length >= 3) {
      currentRow.salePrice = moneyMatches[0].replace(/[^\d\.]/g, '');
      currentRow.tax = moneyMatches[1].replace(/[^\d\.]/g, '');
      currentRow.surplus = moneyMatches[2].replace(/[^\d\.]/g, '');
      foundValidEntries = true;
    }

    // Try to extract location - this is challenging and varies by format
    const afterTownText = line.substring(line.indexOf(town) + town.length).trim();
    const locationMatch = afterTownText.match(/([\d]{4}-[\d]+)\s+(.+?)\s+([\d]{4}\s+[G|S])/i);

    if (locationMatch) {
      currentRow.indexNumber = locationMatch[1];
      currentRow.location = locationMatch[2].trim();
    }

    // Add auction reference data
    currentRow.auctionId = recordId;
  } 
  // Check if this is a continuation of the previous row
  else if (Object.keys(currentRow).length > 0) {
    // Look for dollar amounts if we don't have them yet
    if (!currentRow.salePrice) {
      const moneyMatches = line.match(/\$([\d,]+\.\d{2})/g);
      if (moneyMatches && moneyMatches.length >= 3) {
        currentRow.salePrice = moneyMatches[0].replace(/[^\d\.]/g, '');
        currentRow.tax = moneyMatches[1].replace(/[^\d\.]/g, '');
        currentRow.surplus = moneyMatches[2].replace(/[^\d\.]/g, '');
        foundValidEntries = true;
      }
    }

    // If we don't have a location yet, this might be it
    if (!currentRow.location && !line.includes("$")) {
      currentRow.location = line;
    }
  }
}

// Don't forget the last row
if (Object.keys(currentRow).length > 0) {
  foreclosures.push({...currentRow});
}

// Map to the field names expected by Airtable
const mappedForeclosures = foreclosures.map(f => {
  return {
    Number: f.parcelNumber || '',  // PARCEL number
    SBL: f.sbl || '',  // SBL# field
    "Deed Book": f.indexNumber || '',  // INDEX # field
    Location: f.location || '',
    "Sale Price": parseFloat(f.salePrice) || 0,
    Tax: parseFloat(f.tax) || 0,
    Surplus: parseFloat(f.surplus) || 0,
    Auction: [recordId],  // Link to the auction record
    Town: f.town || '',
    Index: f.indexNumber || ''  // Added Index field
  };
});

// If we found no valid entries with our parsing approach,
// we should recommend using AI for better results
let notes = "";
if (!foundValidEntries) {
  notes = "WARNING: No valid foreclosure entries were detected. Consider using AI parsing.";
}

// Return all foreclosures found with relationship to auction
return {
  json: {
    auctionId: recordId,
    auctionTitle: auctionTitle,
    foreclosuresCount: mappedForeclosures.length,
    notes: notes,
    foreclosures: mappedForeclosures
  }
};
